9640 // Returns a pair (Condition, ConditionIsTrue), where Condition is a branch
9641 // condition dominating ContextI or nullptr, if no condition is found.
9642 static std::pair<Value *, bool>
9643 getDomPredecessorCondition(const Instruction *ContextI) {
9644   if (!ContextI || !ContextI->getParent())
9645     return {nullptr, false};
9646 
9647   // TODO: This is a poor/cheap way to determine dominance. Should we use a
9648   // dominator tree (eg, from a SimplifyQuery) instead?
9649   const BasicBlock *ContextBB = ContextI->getParent();
9650   const BasicBlock *PredBB = ContextBB->getSinglePredecessor();
9651   if (!PredBB)
9652     return {nullptr, false};
9653 
9654   // We need a conditional branch in the predecessor.
9655   Value *PredCond;
9656   BasicBlock *TrueBB, *FalseBB;
9657   if (!match(PredBB->getTerminator(), m_Br(m_Value(PredCond), TrueBB, FalseBB)))
9658     return {nullptr, false};
9659 
9660   // The branch should get simplified. Don't bother simplifying this condition.
9661   if (TrueBB == FalseBB)
9662     return {nullptr, false};
9663 
9664   assert((TrueBB == ContextBB || FalseBB == ContextBB) &&
9665          "Predecessor block does not point to successor?");
9666 
9667   // Is this condition implied by the predecessor condition?
9668   return {PredCond, TrueBB == ContextBB};
9669 }
